import java.util.Scanner;
import java.nio.ByteBuffer;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Use ByteBuffer to safely manage byte buffer
        ByteBuffer buffer = ByteBuffer.allocate(10);

        // Copy user input into the buffer with proper length handling
        byte[] userInputBytes = name.getBytes();

        int copyLength = Math.min(userInputBytes.length, buffer.remaining());
        buffer.put(userInputBytes, 0, copyLength);

        System.out.println("User input copied to buffer successfully.");
    }
}

